INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52977', 'arrabiata', 'Pasta', '1. Cook pasta in salted boiling water until al dente. 2. While pasta cooks, finely chop garlic and red chili peppers. 3. Heat olive oil in a large skillet over medium heat. 4. Add garlic and chili peppers to the oil and fry for a few minutes until fragrant. 5. Add tomatoes and simmer for about 10 minutes. 6. Drain pasta and add to the tomato sauce. 7. Toss well to combine. 8. Serve immediately with grated Pecorino Romano cheese.', '400g spaghetti, 400g canned tomatoes, 3 cloves garlic, 2 red chili peppers, 100ml olive oil, Salt and pepper to taste, Pecorino Romano cheese for serving', 'https://www.themealdb.com/images/media/meals/b6rrjq1508773722.jpg');

INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52809', 'pad thai', 'Asian', '1. Soak rice noodles in room temperature water for 30 minutes until softened. 2. Heat oil in a wok or large pan over high heat. 3. Add garlic and stir fry for 30 seconds. 4. Add shrimp and cook until pink, about 2-3 minutes. 5. Add chicken and stir fry until cooked through. 6. Add drained noodles and stir fry for 2 minutes. 7. Add tamarind juice, fish sauce, and brown sugar. 8. Toss in half the peanuts and all the bean sprouts. 9. Serve garnished with remaining peanuts, cilantro, and lime.', '300g rice noodles, 100g shrimp, 100g chicken, 3 cloves garlic, 2 tbsp tamarind juice, 1 tbsp fish sauce, 1 tbsp brown sugar, 50g peanuts, Bean sprouts, Cilantro, Lime', 'https://www.themealdb.com/images/media/meals/usxxtp1487341333.jpg');

INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52855', 'chocolate chip cookies', 'Dessert', '1. Preheat oven to 375°F (190°C). 2. In a large bowl, cream together butter and sugars until light and fluffy. 3. Beat in eggs one at a time, then add vanilla. 4. In another bowl, combine flour, baking soda, and salt. 5. Gradually blend the dry ingredients into the butter mixture. 6. Stir in chocolate chips. 7. Drop rounded tablespoons of dough onto cookie sheets. 8. Bake for 9-11 minutes or until golden brown. 9. Cool on baking sheet for 2 minutes before removing to a wire rack.', '225g butter, 200g brown sugar, 100g white sugar, 2 eggs, 2 tsp vanilla extract, 280g flour, 1 tsp baking soda, 1 tsp salt, 340g chocolate chips', 'https://www.themealdb.com/images/media/meals/sxxpqt1511590270.jpg');

INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52844', 'breakfast potatoes', 'Breakfast', '1. Dice potatoes into small cubes. 2. Heat olive oil in a large skillet over medium-high heat. 3. Add diced onions and bell peppers, sauté for 3-4 minutes. 4. Add potato cubes and cook for 10-12 minutes, stirring occasionally, until potatoes are golden and crispy. 5. Season with salt, pepper, and paprika. 6. Add garlic and cook for 1 minute more. 7. Serve hot, optionally topped with fried eggs and fresh herbs.', '4 medium potatoes, 1 red bell pepper, 1 onion, 3 cloves garlic, 2 tbsp olive oil, Salt and pepper to taste, 1 tsp paprika, Fresh herbs', 'https://www.themealdb.com/images/media/meals/1550441882.jpg');

INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53050', 'grilled fish with lemon', 'Seafood', '1. Preheat grill to medium-high heat. 2. Pat fish dry and season inside and out with salt and pepper. 3. Stuff fish cavity with lemon slices and fresh herbs. 4. Brush both sides with olive oil. 5. Place fish on grill grates. 6. Grill for 4-5 minutes per side, depending on thickness. 7. Fish is done when flesh flakes easily when tested with a fork. 8. Serve with fresh lemon wedges and additional fresh herbs.', '2 whole fish (1kg), 30ml olive oil, 2 lemons, Fresh herbs (dill or parsley), Salt and pepper to taste, Lemon wedges for serving', 'https://www.themealdb.com/images/media/meals/lfrtxb1562637546.jpg');